query Contacts {
  contacts(
    first: 1



  ) {
    items {
      contactInfo {
        kind
        source
        value
      }
      email
      id
      insertedAt
      integrationReferences {
        crmUrl
        recordId
        recordType
        service
      }
      name
      status
      type
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
